ge']??'Dữ liệu không hợp lệ',$r['errors']??[],422);} public function destroy(string $n,int $id){AuthMiddleware::requireLogin();$s=$this->service($n);if(!$s||$n==='returns')ApiResponse::error('API không hỗ trợ xóa',[],405);$r=$s->delete($id);$r['ok']?ApiResponse::success('Xóa thành công'):ApiResponse::error($r['message']??'Không thể xóa',[],422);} public function undoReturn(int $id){AuthMiddleware::requireLogin();$r=(new ReturnService())->undo($id);$r['ok']?ApiResponse::success('Hoàn tác thành công'):ApiResponse::error($r['message']??'Không thể hoàn tác',[],422);} }
